module counter_up_down(reset, RST, EN, UP_DOWN, COUNT);
input reset, RST, EN, UP_DOWN;
output reg [3:0] COUNT;

always @(posedge reset or posedge RST) begin
    if (RST)
        COUNT <= 4'b0000;
    else if (EN) begin
        if (UP_DOWN)
            COUNT <= COUNT + 1;
        else
            COUNT <= COUNT - 1;
    end
end

endmodule
